(window.webpackJsonp=window.webpackJsonp||[]).push([[903],{1172:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums1</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums2</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> nextGreaterElement = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums1, nums2</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> stack=[],hash={}\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums2.length;i++){\\n    <span class=\\"hljs-keyword\\">while</span>(stack.length&gt;<span class=\\"hljs-number\\">0</span> &amp;&amp; nums2[i]&gt;stack[stack.length<span class=\\"hljs-number\\">-1</span>]){\\n      hash[stack.pop()]=nums2[i]\\n    }\\n    stack.push(nums2[i])\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums1.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(hash[nums1[i]]==<span class=\\"hljs-literal\\">null</span>){\\n      res.push(<span class=\\"hljs-number\\">-1</span>)\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      res.push(hash[nums1[i]])\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"next-greater-element-i","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u53ef\u4ee5\u4f7f\u7528\u66b4\u529b\u89e3\u51b3<code>O(N^2)</code>\uff0c\u66f4\u9ad8\u6548\u7684\u662f<code>O(N)</code>\uff0c\u4f7f\u7528<code>stack</code>\u3002</p>\\n<p>\u5047\u8bbe<code>num2=[1,6,4,5,3,8]</code>\uff0c\u6211\u4eec\u901a\u8fc7<code>stack</code>\u4e0d\u65ad\u538b\u6808</p>\\n<ol>\\n<li><code>cur===1</code>\uff0c<code>stack=[1]</code>\u3002</li>\\n<li><code>cur===6</code>\uff0c<code>cur&gt;stack[stack.length-1]</code>\uff0c\u56e0\u6b64\u8bf4\u660e<code>1</code>\u7684\u4e0b\u4e00\u4e2a\u6700\u5927\u503c\u5c31\u662f<code>6</code>\uff0c\u901a\u8fc7<code>hash</code>\u4fdd\u5b58\u5e76\u4e14<code>stack.pop</code>\u3002</li>\\n<li><code>cur===4</code>\uff0c<code>stack=[6,4]</code>\u3002</li>\\n<li><code>cur===5</code>\uff0c<code>cur&gt;stack[stack.length-1]</code>\uff0c\u8bf4\u660e<code>4</code>\u7684\u4e0b\u4e00\u4e2a\u6700\u5927\u503c\u662f<code>5</code>\u3002</li>\\n<li><code>cur===3</code>\uff0c<code>stack=[6,5,3]</code>\u3002</li>\\n<li><code>cur===8</code>\uff0c<code>5</code>\u548c<code>3</code>\u7684\u4e0b\u4e00\u4e2a\u6700\u5927\u503c\u662f<code>8</code>\u3002</li>\\n</ol>\\n<p>\u63a5\u7740\u904d\u5386<code>nums1</code>\uff0c\u53ea\u9700\u8981\u68c0\u67e5<code>hash</code>\u4e2d\u7684\u4e0b\u4e00\u4e2a\u6700\u5927\u503c\u5373\u53ef\uff0c\u4e0d\u5b58\u5728\u5219\u4e3a<code>-1</code>\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e24\u4e2a<strong> \u6ca1\u6709\u91cd\u590d\u5143\u7d20</strong> \u7684\u6570\u7ec4\xa0<code>nums1</code> \u548c\xa0<code>nums2</code>\xa0\uff0c\u5176\u4e2d<code>nums1</code>\xa0\u662f\xa0<code>nums2</code>\xa0\u7684\u5b50\u96c6\u3002</p>\\n\\n<p>\u8bf7\u4f60\u627e\u51fa <code>nums1</code>\xa0\u4e2d\u6bcf\u4e2a\u5143\u7d20\u5728\xa0<code>nums2</code>\xa0\u4e2d\u7684\u4e0b\u4e00\u4e2a\u6bd4\u5176\u5927\u7684\u503c\u3002</p>\\n\\n<p><code>nums1</code>\xa0\u4e2d\u6570\u5b57\xa0<code>x</code>\xa0\u7684\u4e0b\u4e00\u4e2a\u66f4\u5927\u5143\u7d20\u662f\u6307\xa0<code>x</code>\xa0\u5728\xa0<code>nums2</code>\xa0\u4e2d\u5bf9\u5e94\u4f4d\u7f6e\u7684\u53f3\u8fb9\u7684\u7b2c\u4e00\u4e2a\u6bd4\xa0<code>x</code><strong>\xa0</strong>\u5927\u7684\u5143\u7d20\u3002\u5982\u679c\u4e0d\u5b58\u5728\uff0c\u5bf9\u5e94\u4f4d\u7f6e\u8f93\u51fa <code>-1</code> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1:</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165:</strong> nums1 = [4,1,2], nums2 = [1,3,4,2].\\n<strong>\u8f93\u51fa:</strong> [-1,3,-1]\\n<strong>\u89e3\u91ca:</strong>\\n    \u5bf9\u4e8e num1 \u4e2d\u7684\u6570\u5b57 4 \uff0c\u4f60\u65e0\u6cd5\u5728\u7b2c\u4e8c\u4e2a\u6570\u7ec4\u4e2d\u627e\u5230\u4e0b\u4e00\u4e2a\u66f4\u5927\u7684\u6570\u5b57\uff0c\u56e0\u6b64\u8f93\u51fa -1 \u3002\\n    \u5bf9\u4e8e num1 \u4e2d\u7684\u6570\u5b57 1 \uff0c\u7b2c\u4e8c\u4e2a\u6570\u7ec4\u4e2d\u6570\u5b571\u53f3\u8fb9\u7684\u4e0b\u4e00\u4e2a\u8f83\u5927\u6570\u5b57\u662f 3 \u3002\\n    \u5bf9\u4e8e num1 \u4e2d\u7684\u6570\u5b57 2 \uff0c\u7b2c\u4e8c\u4e2a\u6570\u7ec4\u4e2d\u6ca1\u6709\u4e0b\u4e00\u4e2a\u66f4\u5927\u7684\u6570\u5b57\uff0c\u56e0\u6b64\u8f93\u51fa -1 \u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2:</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165:</strong> nums1 = [2,4], nums2 = [1,2,3,4].\\n<strong>\u8f93\u51fa:</strong> [3,-1]\\n<strong>\u89e3\u91ca:</strong>\\n\xa0   \u5bf9\u4e8e num1 \u4e2d\u7684\u6570\u5b57 2 \uff0c\u7b2c\u4e8c\u4e2a\u6570\u7ec4\u4e2d\u7684\u4e0b\u4e00\u4e2a\u8f83\u5927\u6570\u5b57\u662f 3 \u3002\\n    \u5bf9\u4e8e num1 \u4e2d\u7684\u6570\u5b57 4 \uff0c\u7b2c\u4e8c\u4e2a\u6570\u7ec4\u4e2d\u6ca1\u6709\u4e0b\u4e00\u4e2a\u66f4\u5927\u7684\u6570\u5b57\uff0c\u56e0\u6b64\u8f93\u51fa -1 \u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums1.length <= nums2.length <= 1000</code></li>\\n\\t<li><code>0 <= nums1[i], nums2[i] <= 10<sup>4</sup></code></li>\\n\\t<li><code>nums1</code>\u548c<code>nums2</code>\u4e2d\u6240\u6709\u6574\u6570 <strong>\u4e92\u4e0d\u76f8\u540c</strong></li>\\n\\t<li><code>nums1</code> \u4e2d\u7684\u6240\u6709\u6574\u6570\u540c\u6837\u51fa\u73b0\u5728 <code>nums2</code> \u4e2d</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong>\u4f60\u53ef\u4ee5\u8bbe\u8ba1\u4e00\u4e2a\u65f6\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(nums1.length + nums2.length)</code> \u7684\u89e3\u51b3\u65b9\u6848\u5417\uff1f</p>\\n","title":"496. \u4e0b\u4e00\u4e2a\u66f4\u5927\u5143\u7d20 I","relatedTags":["\u6808"],"difficult":"Easy","lang":["javascript"],"uniqueID":"496"}')}}]);